import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development: return "https://api.dev.example.com"
        case .staging: return "https://api.staging.example.com"
        case .production: return "https://api.example.com"
        }
    }
}

enum APIError: Error {
    case invalidURL
    case noData
    case decodingFailed
    case serverError(Int)
}

class APIService {
    static let shared = APIService()
    private let session: URLSession
    private let environment: Environment
    
    private init(environment: Environment = .production) {
        self.environment = environment
        let config = URLSessionConfiguration.default
        config.timeoutInterval = 30
        self.session = URLSession(configuration: config)
    }
    
    func fetchUserData(completion: @escaping (Result<User, APIError>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/users/me") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.decodingFailed))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let user = try JSONDecoder().decode(User.self, from: data)
                completion(.success(user))
            } catch {
                completion(.failure(.decodingFailed))
            }
        }
        
        task.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<AuthResponse, APIError>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/auth/login") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body = ["username": username, "password": password]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.decodingFailed))
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let authResponse = try JSONDecoder().decode(AuthResponse.self, from: data)
                completion(.success(authResponse))
            } catch {
                completion(.failure(.decodingFailed))
            }
        }
        
        task.resume()
    }
}

struct User: Codable {
    let id: String
    let name: String
    let email: String
}

struct AuthResponse: Codable {
    let token: String
    let user: User
}